import scala.util.matching.Regex

def solve(code: Array[String], businessLine: Array[String], isActive: Array[Boolean]): Array[String] = {
  val validBusinessLines = Set("electronics", "grocery", "pharmacy", "restaurant")
  val pattern: Regex = "^[a-zA-Z0-9_]+$".r

  // Zip the three arrays together and process each coupon
  val validCoupons = (code, businessLine, isActive).zipped.toArray.flatMap {
    case (c, bl, active) =>
      if (c.nonEmpty && pattern.matches(c) && validBusinessLines.contains(bl) && active) {
        Some((bl, c))
      } else {
        None
      }
  }

  // Define the order of business lines for sorting
  val businessLineOrder = Map(
    "electronics" -> 0,
    "grocery" -> 1,
    "pharmacy" -> 2,
    "restaurant" -> 3
  )

  // Sort the coupons first by business line order, then by code
  val sortedCoupons = validCoupons.sortBy { case (bl, c) =>
    (businessLineOrder(bl), c)
  }

  // Extract the codes in order
  sortedCoupons.map(_._2)
}
